/**
 * @feature Apply - Happy Path - SF-424 Application Submission and Print View Workflow
 * @scenario Complete the SF-424 Application Submission and Print View workflow for an <user type> user
 *
 * NOTE:
 * Submitted application creates a downloadable ZIP containing PDF/XML artifacts generated by the system.
 * This spec validates the print view output instead of directly validating the generated ZIP/PDF artifact.
 * The print view acts as a pre-PDF rendering validation layer to confirm submitted data renders correctly.
 *
 * Opportunity: TEST-SF424-ORG-IND-01 (SF-424 form – local + staging)
 * Form: Application for Federal Assistance (SF-424)
 *
 * To add a new opportunity:
 *   1. Create a per-form data file at tests/e2e/apply/fixtures/<form>-data.ts
 *      and export a `PrintViewFormData` const with opportunityId, opportunityNumber,
 *      formKey, and expectedPrepopulatedFields.
 *   2. Import that export into PRINT_VIEW_FORM_DATA in tests/e2e/utils/submission/load-opportunity-config.ts
 *   3. Add the form's FillFormConfig to FORM_CONFIG_REGISTRY in the same file.
 *   4. Add a happy-path builder as `buildTestData` in the form's data fixture file.
 *
 * Examples:
 * | user type    | who is applying           |
 * | Organization | Organization A            |
 * | Individual   | As an individual (myself) |
 */

import {
  expect,
  test,
  type BrowserContext,
  type Page,
  type TestInfo,
} from "@playwright/test";
import playwrightEnv from "tests/e2e/playwright-env";
import { VALID_TAGS } from "tests/e2e/tags";
import { authenticateE2eUser } from "tests/e2e/utils/authenticate-e2e-user-utils";
import { createApplication } from "tests/e2e/utils/create-application-utils";
import { fillForm } from "tests/e2e/utils/forms/general-forms-filling";
import {
  verifyFormStatusAfterSave,
  verifyFormStatusOnApplication,
} from "tests/e2e/utils/forms/verify-form-status-utils";
import { loadOpportunityConfig } from "tests/e2e/utils/submission/load-opportunity-config";
import type { FilledFormEntry } from "tests/e2e/utils/submission/opportunity-print-view.types";
import {
  buildHappyPathTestData,
  buildPrintUrl,
  navigateToPrintView,
} from "tests/e2e/utils/submission/print-view-utils";
import { submitApplicationAndVerify } from "tests/e2e/utils/submission/submit-application-utils";

const { APPLY, APPLY_FORMS, CORE_REGRESSION, SMOKE, GRANTEE } = VALID_TAGS;

const { testOrgLabel, targetEnv } = playwrightEnv;

// Only the opportunity number is declared here.
// All opportunity/form details are resolved from the per-form data files via load-opportunity-config.ts.
const OPPORTUNITY_NUMBER = "TEST-SF424-ORG-IND-01";
const opportunityConfig = loadOpportunityConfig(OPPORTUNITY_NUMBER);

const applicantScenarios = [
  {
    testName: `Complete the SF-424 Application Submission and Print View workflow for an Organization user`,
    orgLabel: testOrgLabel,
  },
  {
    testName: `Complete the SF-424 Application Submission and Print View workflow for an Individual user`,
    orgLabel: undefined,
  },
] as const;

// Skip non-Chrome browsers in staging to avoid MFA OTP rate-limiting.
test.beforeEach(({ page: _ }, testInfo) => {
  if (targetEnv === "staging") {
    test.skip(
      testInfo.project.name !== "Chrome",
      "Staging MFA login is limited to Chrome to avoid OTP rate-limiting",
    );
  }
});

for (const { testName, orgLabel } of applicantScenarios) {
  test(
    testName,
    { tag: [SMOKE, GRANTEE, APPLY, APPLY_FORMS, CORE_REGRESSION] },
    async (
      { page, context }: { page: Page; context: BrowserContext },
      testInfo: TestInfo,
    ) => {
      test.setTimeout(300_000); // 5-min timeout

      const isMobile = testInfo.project.name.match(/[Mm]obile/);
      const baseSuffix = Date.now();

      // --- Login ---
      // Given the user is logged in
      await authenticateE2eUser(page, context, !!isMobile);

      // --- Navigate to Opportunity page and start a new application ---
      // And the user launches the URL for an opportunity with an open SF-424 competition
      // When the user clicks "Start Application", selects applicant type and creates the application
      await createApplication(page, opportunityConfig.opportunityUrl, orgLabel);
      const applicationUrl = page.url();

      // --- Fill required forms and collect print URLs ---
      // For each form on this opportunity: fill it, verify status, then capture the
      // form URL *before* verifyFormStatusOnApplication navigates away to the app page.
      const filledForms: FilledFormEntry[] = [];

      for (const [index, form] of opportunityConfig.forms.entries()) {
        const testData = buildHappyPathTestData(
          form.buildTestData,
          baseSuffix + index,
          form.formConfig,
        );

        await fillForm(testInfo, page, form.formConfig, testData, false);

        // Verify save succeeded while still on the form page
        await verifyFormStatusAfterSave(page, "complete");

        // Capture the form URL now - verifyFormStatusOnApplication navigates away
        const formUrl = page.url();

        await verifyFormStatusOnApplication(
          page,
          "complete",
          form.formConfig.formName,
          applicationUrl,
        );

        filledForms.push({
          formKey: form.formKey,
          formName: form.formConfig.formName,
          testData,
          printUrl: buildPrintUrl(formUrl),
          expectedPrepopulatedFields: form.expectedPrepopulatedFields,
          userEnteredFieldTestIds: form.userEnteredFieldTestIds,
        });
      }

      // Return to application landing page before submitting
      await page.goto(applicationUrl);
      await page.waitForLoadState("domcontentloaded");

      // --- Submit Application ---
      // When the user clicks "Submit application"
      // Then the application is submitted successfully
      await submitApplicationAndVerify(page, "success");

      // --- Confirmation Page Validation ---
      await expect(
        page.getByRole("heading", {
          name: /your application has been submitted/i,
        }),
      ).toBeVisible();

      await expect(page.getByTestId("summary-box")).toContainText(
        "Your application has been submitted",
      );

      // --- Print View Validation (one page per form) ---
      for (const {
        formKey,
        testData,
        printUrl,
        expectedPrepopulatedFields,
        userEnteredFieldTestIds,
        formName,
      } of filledForms) {
        await navigateToPrintView(page, printUrl);

        // Form title heading is visible
        await expect(page.locator("h1")).toContainText(formName);

        // Pre-populated fields (API-injected from opportunity record)
        for (const [testId, expectedValue] of Object.entries(
          expectedPrepopulatedFields,
        )) {
          await expect(page.getByTestId(testId)).toBeVisible();
          await expect(page.getByTestId(testId)).toContainText(expectedValue);
        }

        // User-entered fields — testIds derived from formConfig.fields (printTestId ?? testId)
        // Skip fields not present in testData (e.g. revision_type for non-Revision applications)
        for (const [dataKey, testId] of Object.entries(
          userEnteredFieldTestIds,
        )) {
          if (testData[dataKey] === undefined) continue;
          await expect(page.getByTestId(testId)).toBeVisible();
          await expect(page.getByTestId(testId)).toContainText(
            testData[dataKey],
          );
        }

        // SF-424 attachment sections — filenames appear in list items inside the
        // section, not in testId elements, so validated by section locator.
        if (formKey === "sf424") {
          const attachmentFileName = (filePath: string) =>
            filePath.split(/[/\\]/).pop() ?? filePath;

          const sf424AttachmentSections = [
            {
              fieldKey: "areas_affected_attachment",
              sectionId: "form-section-areas_affected",
            },
            {
              fieldKey: "additional_project_title_attachment",
              sectionId: "form-section-project_title",
            },
            {
              fieldKey: "additional_congressional_attachment",
              sectionId: "form-section-congressional_districts",
            },
          ] as const;

          for (const { fieldKey, sectionId } of sf424AttachmentSections) {
            if (testData[fieldKey]) {
              const fileName = attachmentFileName(testData[fieldKey]);
              await expect(
                page.locator(`#${sectionId}`).getByRole("listitem"),
              ).toBeVisible();
              await expect(page.locator(`#${sectionId}`)).toContainText(
                fileName,
              );
            }
          }
        }
      }
    },
  );
}
